-- Equalizer schema v3: move practice questions from hardcoded JS into the database
-- Run this once in the Supabase SQL Editor (Project → SQL Editor → New query → Run).

create table public.questions (
  id bigint generated always as identity primary key,
  subject text not null check (subject in ('tj','acl')),
  category text not null,
  question text not null,
  options jsonb not null,
  answer_index int not null,
  explanation text not null,
  created_at timestamptz not null default now()
);

alter table public.questions enable row level security;
create policy "questions are publicly readable" on public.questions for select using (true);

