insert into public.questions (subject, category, question, options, answer_index, explanation) values
('tj', 'Math/Quant', 'If x is an integer, which of the following must also be an integer?', '["\u2212x", "x/2", "2/x", "\u221ax"]'::jsonb, 0, 'The negative of any integer is always an integer. The other options fail for many integers (e.g. x=3: x/2=1.5, 2/x=0.67, √x isn''t whole). ✓'),
('tj', 'Math/Quant', 'In January 2011, the national debt was about 14 trillion dollars and the US population was about 300 million. Someone estimated the debt was about $5,000 per person. How reasonable is this estimate?', '["It is too low by a factor of 10", "It is too low by a factor of 100", "It is too high by a factor of 10", "It is too high by a factor of 100"]'::jsonb, 0, 'Actual = 14,000,000,000,000 ÷ 300,000,000 ≈ $46,667 per person. That''s about 9-10× more than the $5,000 estimate, so the estimate is too low by roughly a factor of 10. ✓'),
('tj', 'Math/Quant', 'What is the probability that two randomly selected people were born on the same day of the week? Assume all days are equally probable.', '["1/7", "1/14", "1/42", "1/49"]'::jsonb, 0, 'The first person''s day doesn''t matter. The second person just needs to match that day: probability = 1/7. ✓'),
('tj', 'Math/Quant', 'T-shirts are on sale for 20% off. Sonia paid $8.73 for a shirt. Let p represent the regular price. Which equation is correct?', '["0.8p = $8.73", "$8.73 + 0.2\u00d7$8.73 = p", "1.2\u00d7$8.73 = p", "p \u2212 0.2\u00d7$8.73 = p"]'::jsonb, 0, '20% off means she paid 80% of the regular price: 0.8p = $8.73. ✓'),
('tj', 'Spatial/Geometric', 'How many lines of reflective symmetry and centers of rotational symmetry does a (non-rectangular, non-rhombus) parallelogram have?', '["2 lines of reflective symmetry and one center of rotational symmetry", "0 lines of reflective symmetry and one center of rotational symmetry", "4 lines of reflective symmetry and one center of rotational symmetry", "2 lines of reflective symmetry and no center of rotational symmetry"]'::jsonb, 1, 'A generic parallelogram has no mirror-symmetry lines, but rotating it 180° about its center maps it onto itself — one center of rotational symmetry. ✓'),
('tj', 'Math/Quant', 'A pattern shows a row of black squares surrounded by a 1-square-thick white border (forming a 3-row rectangle). How many white squares would surround a row of 157 black squares?', '["320", "324", "327", "336"]'::jsonb, 0, 'For n black squares, the whole shape is 3 rows × (n+2) columns, all white except the n black squares in the middle row: white = 3(n+2) − n = 2n + 6. For n=157: 2(157)+6 = 320. ✓'),
('tj', 'Math/Quant', 'ADA regulations require wheelchair ramp slope ≤ 1:12 (preferably 1:16–1:20) and max rise of 30 inches. Based on the graph of rise vs. run for ramps B, C, and D, which ramp complies?', '["B", "C", "D", "None of these"]'::jsonb, 0, 'Ramp B (~22 ft run, ~1.8 ft rise) gives a slope of about 1:12.2 — within the 1:12 max — and a rise of about 21.6 in, under the 30 in cap. Ramp C is far too steep (~1:7), failing the slope requirement. ✓'),
('tj', 'Math/Quant', 'The speed of sound in dry air at 68°F is 343.2 meters per second. Which expression computes the kilometers traveled by a sound wave in 10 minutes?', '["343.2\u00d760\u00d710", "343.2\u00d760\u00d710\u00d7(1/1000)", "343.2\u00d7(1/60)\u00d710", "343.2\u00d7(1/60)\u00d710\u00d7(1/1000)"]'::jsonb, 1, '10 minutes = 600 seconds = 60×10. Meters traveled = 343.2 × 60 × 10. Divide by 1000 to convert to kilometers. ✓'),
('tj', 'Math/Quant', 'On a map, Boston to Detroit is 6 cm and the actual distance is 702 miles. Using the same scale, what map distance is closest to the actual 2,708 miles between Boston and San Francisco?', '["21 cm", "22 cm", "23 cm", "25 cm"]'::jsonb, 2, 'Scale: 6 cm / 702 mi. Map distance = 6 × (2708/702) ≈ 23.1 cm, closest to 23 cm. ✓'),
('tj', 'Spatial/Geometric', 'What set of transformations will transform the leftmost L-shaped figure into the rightmost one?', '["A 90\u00b0 clockwise rotation about (2,1) followed by a translation of two units to the right", "A translation 3 units up, followed by a reflection about the line y = x", "A 90\u00b0 clockwise rotation about (5,1), followed by a translation of 2 units up", "A 90\u00b0 clockwise rotation about (2,1) followed by a translation of 2 units to the right"]'::jsonb, 0, 'Rotating the shape 90° clockwise about the point (2,1) and then sliding it two units right lands it exactly on the target figure. ✓'),
('tj', 'Logic/Reasoning', 'A study examines the relation between body cameras on police officers and rising deaths of officers in action. Which question is irrelevant to the research?', '["Are the body cameras distracting the police officers?", "Are there more police officers in the force now than before?", "Is smoking weed bad for police?", "Are police given proper training on using body cameras in action?"]'::jsonb, 2, 'Whether smoking is ''bad for police'' has nothing to do with body cameras or officer deaths in action — it''s off-topic. ✓'),
('tj', 'Logic/Reasoning', 'Amy came back from jogging feeling tired and cold. Bianca heard 18% of the town has the flu. Amy asks if she really has the flu. What''s the most logical reply?', '["You definitely have the flu", "Maybe Amy. But, perhaps not", "You have an 18% chance of having flu", "Let''s hope you do not have the flu"]'::jsonb, 1, 'Tiredness and cold could be the flu or something else entirely (exertion, weather). The honest, logical answer acknowledges the uncertainty. ✓'),
('tj', 'Math/Quant', 'If the sum of base (B) and height (H) of a triangle is constant, what must be true for the area to be at its maximum?', '["B = H", "B = 2H", "B = 0.5H", "B = 0.3H"]'::jsonb, 0, 'For a fixed sum, the product of two numbers is maximized when they''re equal (basic optimization result) — so B = H maximizes Area = ½BH. ✓'),
('tj', 'Math/Quant', 'A city''s transportation study found 60 buses, 285 cars, and 387 motorcycles crossing a junction. A pie chart shows Motorcycles=210°, Buses=30°, Cars=120°. Does this pie chart correctly represent the data?', '["Yes", "No", "May be", "Cannot be determined"]'::jsonb, 1, 'Total = 732. Expected angles: buses ≈30° (matches), cars ≈285/732×360≈140° (chart shows 120° — wrong), motorcycles ≈387/732×360≈190° (chart shows 210° — wrong). The chart is inaccurate. ✓'),
('tj', 'Math/Quant', 'A table shows buyer percentages for soap brands: A=20%, B=35%, C=30%, D=15%. If shown in a pie chart, what is the sector angle for brand D?', '["60\u00b0", "72\u00b0", "45\u00b0", "54\u00b0"]'::jsonb, 3, 'Sector angle = percentage × 360°. For D: 0.15 × 360 = 54°. ✓'),
('tj', 'Spatial/Geometric', 'A big cube assembled from 216 unit cubes (6×6×6) is cut at a 45° angle starting from one of its edges. How many unit cubes are cut in the process?', '["24", "36", "48", "60", "72"]'::jsonb, 1, 'For an n×n×n cube (n=6), a 45° diagonal plane cut starting along one edge slices through n² = 36 unit cubes. ✓'),
('tj', 'Spatial/Geometric', 'A big cube assembled from 125 unit cubes (5×5×5) is cut at a 45° angle starting from one of its corners. How many unit cubes are cut in the process?', '["30", "25", "20", "15", "10"]'::jsonb, 1, 'For an n×n×n cube (n=5), the diagonal cutting plane passes through n² = 25 unit cubes. ✓'),
('tj', 'Spatial/Geometric', 'If the pattern triangle, square, pentagon, hexagon... continues, what shape does it approach?', '["A cube", "A point", "A circle", "Cannot be determined"]'::jsonb, 2, 'As the number of sides of a regular polygon increases without bound, the shape approaches a circle. ✓'),
('tj', 'Math/Quant', 'Amy invested $10,000 in a stock that increases 2% per year. What is the value at the end of the second year?', '["$10,240", "$10,400", "$10,404", "$10,440"]'::jsonb, 2, 'Value = $10,000 × 1.02² = $10,000 × 1.0404 = $10,404. ✓'),
('tj', 'Math/Quant', 'John''s stock increased 10% in value in year one and lost 20% in year two. What is the net percentage change over the two years?', '["6% decrease", "8% decrease", "10% decrease", "12% decrease"]'::jsonb, 3, 'Net factor = 1.10 × 0.80 = 0.88, which is a 12% decrease from the original value. ✓'),
('tj', 'Spatial/Geometric', 'A cube painted red is cut into 125 unit cubes (5×5×5). How many unit cubes have exactly two faces painted red?', '["27", "36", "44", "54"]'::jsonb, 1, 'Edge cubes (excluding corners) have exactly 2 painted faces: 12 edges × (n−2) = 12 × 3 = 36 for n=5. ✓'),
('tj', 'Math/Quant', 'A kitchen sink holds 21 gallons. The faucet adds 1 gallon every 20 seconds. Once the sink reaches 18 gallons, an outlet also removes 1 gallon every 40 seconds. Nila turns on the faucet (sink starts empty) and leaves. How many minutes until the sink overflows?', '["8", "7", "6", "5.5"]'::jsonb, 0, 'Filling to 18 gal at 3 gal/min takes 6 min. From 18 to 21 gal (3 more gallons), net rate = 3 − 1.5 = 1.5 gal/min, taking 2 more minutes. Total = 6 + 2 = 8 minutes. ✓'),
('tj', 'Logic/Reasoning', 'In a circuit, bulb B1 is wired directly in the main loop with the battery, while bulbs B2 and B3 each sit on their own switch (S1, S2) in parallel branches. Which switch positions make bulb B1 glow?', '["Close S1 only", "Close S2 only", "Close both S1 and S2", "All of these"]'::jsonb, 3, 'Since B1''s branch has no switch and is always connected to the battery, it glows regardless of what S1 and S2 are doing. ✓'),
('tj', 'Spatial/Geometric', 'A sphere is cut 6 times, all cuts passing through a common axis (like slicing an orange), evenly spaced. What is the greatest number of pieces possible?', '["6", "8", "10", "12"]'::jsonb, 3, 'n cuts through a common axis produce 2n pieces (like a pizza cut through the center). For n=6: 2×6 = 12 pieces. ✓'),
('tj', 'Logic/Reasoning', 'Nina worries about being selected for a school concert. Valarie tells her, ''You''re one of the best musicians, and everyone who is good gets a chance to perform, so you''ll certainly get a chance.'' Assuming Valarie''s premise about Nina''s talent is true, is her conclusion true?', '["Cannot be false", "Cannot be true", "Probably true, but may be false", "Probably false, but may be true"]'::jsonb, 0, 'If ''everyone good gets a chance'' (universal) and Nina is good, then logically Nina must get a chance — this is a valid syllogism, so the conclusion cannot be false. ✓'),
('tj', 'Spatial/Geometric', 'A hexagonal pool (1 m high) holds 75 cubic meters. A second pool has the same hexagonal shape but with sides twice as long, also 1 m high. How much water does it hold?', '["75 cubic meters", "150 cubic meters", "300 cubic meters", "600 cubic meters"]'::jsonb, 2, 'Doubling the side length of a 2D shape quadruples its area. Volume = new area × height = 4 × 75 × 1 = 300 m³. ✓'),
('tj', 'Math/Quant', 'Nuts normally cost $4.99/lb. Gordon wants 3 pounds. Store A: buy 2, get 3rd half price. Store B: 15% off per pound. Store C: 1/4 off of three pounds. Store D: $1 off per pound. Which store is cheapest?', '["Store A", "Store B", "Store C", "Store D"]'::jsonb, 2, 'A: 2(4.99)+0.5(4.99) = $12.48. B: 3(4.99)(0.85) = $12.72. C: 3(4.99)(0.75) = $11.23. D: 3(4.99−1) = $11.97. Store C is cheapest. ✓'),
('tj', 'Math/Quant', 'M is a multiple of 26. Which of the following cannot be true?', '["M is odd", "M is a multiple of 3", "M is 26", "M is 0"]'::jsonb, 0, '26 is even, so every multiple of 26 is even — M can never be odd. (M=78 is a multiple of 3, M=26 works, and 0 is a multiple of every integer.) ✓'),
('tj', 'Math/Quant', 'Two friends had lunch using a two-for-one coupon, plus tax and a fixed 15% tip on the food charges. What was their percentage savings on the whole transaction (compared to paying full price for both meals)?', '["30%", "40%", "50%", "Cannot be determined"]'::jsonb, 2, 'Paying for one meal instead of two — with tax and tip scaling proportionally with the food charge — works out to exactly half the total bill either way, so savings = 50%. ✓'),
('tj', 'Math/Quant', 'The Eagles finished a baseball season winning 10 more games than they lost. What was their winning percentage?', '["70%", "65%", "60%", "Cannot be determined"]'::jsonb, 3, 'Without knowing the total number of games played, a fixed margin of 10 wins over losses doesn''t pin down a winning percentage (11-1 and 20-10 both fit ''won 10 more'' but give very different percentages). ✓'),
('tj', 'Math/Quant', 'Every home in a neighborhood has at least one car. 24 homes own at least one foreign car, 18 own at least one American car, and 4 own both. How many homes are in the neighborhood?', '["46", "38", "22", "Cannot be determined"]'::jsonb, 1, 'By inclusion-exclusion, homes with at least one car = 24 + 18 − 4 = 38, and since every home has a car, that''s the total. ✓'),
('tj', 'Logic/Reasoning', 'Amy worries about being selected for the regional tournament. Elena tells Amy, "You''re one of the most dedicated people at painting, and everyone who is dedicated gets a spot, so you''ll certainly get a spot." Assuming Elena''s premise about Amy''s talent is true, is the conclusion true?', '["Cannot be true", "Probably false, but may be true", "Probably true, but may be false", "Cannot be false"]'::jsonb, 3, 'If ''everyone dedicated gets a spot'' (universal) and Amy is dedicated, then logically Amy must get a spot — this is a valid syllogism, so the conclusion cannot be false. ✓'),
('tj', 'Math/Quant', 'Grace invested $2,000.00 in an account that grows 6% per year. What is the value at the end of year 4?', '["$2,480.00", "$1,561.50", "$2,382.03", "$2,524.95"]'::jsonb, 3, 'Compound growth: value = $2,000.00 × 1.06^4 = $2,524.95. ✓'),
('tj', 'Logic/Reasoning', 'In a gear train A→B→C→D→E→F where Gear A rotates counter-clockwise, which direction does Gear F move?', '["clockwise", "In either direction", "Cannot be determined", "counter-clockwise"]'::jsonb, 0, 'Every meshed gear alternates direction from the one before it. Gear F is 5 steps from Gear A, so it ends up rotating clockwise. ✓'),
('tj', 'Math/Quant', 'A company''s value increased 40% in year one and decreased 25% in year two. What is the net percentage change over the two years?', '["15% decrease", "65% decrease", "5.0% increase", "15% increase"]'::jsonb, 2, 'Net factor = 1.4 × 0.75 = 1.05, a 5.0% increase. ✓'),
('tj', 'Math/Quant', 'Maya invested $1,000.00 in an account that grows 4% per year. What is the value at the end of year 3?', '["$884.74", "$1,120.00", "$1,124.86", "$1,081.60"]'::jsonb, 2, 'Compound growth: value = $1,000.00 × 1.04^3 = $1,124.86. ✓'),
('tj', 'Logic/Reasoning', 'Theo worries about being selected for the recital. Jamal tells Theo, "You''re one of the most talented people at coding, and everyone who is talented gets a spot, so you''ll certainly get a spot." Assuming Jamal''s premise about Theo''s talent is true, is the conclusion true?', '["Cannot be true", "Cannot be false", "Probably false, but may be true", "Probably true, but may be false"]'::jsonb, 1, 'If ''everyone talented gets a spot'' (universal) and Theo is talented, then logically Theo must get a spot — this is a valid syllogism, so the conclusion cannot be false. ✓'),
('tj', 'Logic/Reasoning', 'Ben worries about being selected for the talent show. Milo tells Ben, "You''re one of the most skilled people at debate, and everyone who is skilled gets a spot, so you''ll certainly get a spot." Assuming Milo''s premise about Ben''s talent is true, is the conclusion true?', '["Probably true, but may be false", "Probably false, but may be true", "Cannot be false", "Cannot be true"]'::jsonb, 2, 'If ''everyone skilled gets a spot'' (universal) and Ben is skilled, then logically Ben must get a spot — this is a valid syllogism, so the conclusion cannot be false. ✓'),
('tj', 'Spatial/Geometric', 'A sphere is cut 8 times, all cuts passing through a common axis, evenly spaced. What is the greatest number of pieces possible?', '["18", "8", "16", "15"]'::jsonb, 2, 'n cuts through a common axis produce 2n pieces (like a pizza cut through the center). For n=8: 2×8 = 16 pieces. ✓'),
('tj', 'Spatial/Geometric', 'A cube painted red on all outer faces is cut into 729 unit cubes (9×9×9). How many unit cubes have exactly two faces painted red?', '["8", "84", "343", "294"]'::jsonb, 1, 'Edge cubes (excluding corners) have exactly 2 painted faces: 12 edges × (n−2) = 12 × 7 = 84 for n=9. ✓'),
('tj', 'Logic/Reasoning', 'In a gear train A→B→C where Gear A rotates clockwise, which direction does Gear C move?', '["clockwise", "In either direction", "Cannot be determined", "counter-clockwise"]'::jsonb, 0, 'Every meshed gear alternates direction from the one before it. Gear C is 2 steps from Gear A, so it ends up rotating clockwise. ✓'),
('tj', 'Spatial/Geometric', 'What is the maximum number of 4-inch wooden cubes that fit in a 1.5 ft × 2 ft × 3 ft box?', '["240", "212", "246", "216"]'::jsonb, 3, 'Convert to inches: 18×24×36. Cubes per dimension: 18/4=4, 24/4=6, 36/4=9. Total = 4×6×9 = 216. ✓'),
('tj', 'Spatial/Geometric', 'A sphere is cut 5 times, all cuts passing through a common axis, evenly spaced. What is the greatest number of pieces possible?', '["9", "5", "12", "10"]'::jsonb, 3, 'n cuts through a common axis produce 2n pieces (like a pizza cut through the center). For n=5: 2×5 = 10 pieces. ✓'),
('tj', 'Spatial/Geometric', 'A cube painted red on all outer faces is cut into 125 unit cubes (5×5×5). How many unit cubes have exactly two faces painted red?', '["36", "8", "27", "54"]'::jsonb, 0, 'Edge cubes (excluding corners) have exactly 2 painted faces: 12 edges × (n−2) = 12 × 3 = 36 for n=5. ✓'),
('tj', 'Logic/Reasoning', 'A contractor was supposed to install concrete letters spelling STONE but installed SETNO by mistake. What is the least number of letter swaps needed to fix it?', '["1", "2", "3", "4"]'::jsonb, 1, 'Comparing SETNO to STONE position by position and tracing the misplaced letters into swap cycles gives a minimum of 2 swap(s) to correct. ✓'),
('tj', 'Math/Quant', 'A company''s value increased 30% in year one and decreased 25% in year two. What is the net percentage change over the two years?', '["5% increase", "5% decrease", "55% increase", "2.5% decrease"]'::jsonb, 3, 'Net factor = 1.3 × 0.75 = 0.975, a 2.5% decrease. ✓'),
('tj', 'Logic/Reasoning', 'A study examines the relationship between plant watering frequency and growth rate. Which question is irrelevant to the research?', '["Could a third factor be influencing both variables?", "Is the greenhouse humid in summer?", "Does more frequent watering increase growth?", "What color are the pots the plants are in?"]'::jsonb, 3, '"What color are the pots the plants are in?" has nothing to do with plant watering frequency and growth rate — it''s off-topic for this research question. ✓'),
('tj', 'Logic/Reasoning', 'A contractor was supposed to install concrete letters spelling BRAVE but installed BRVAE by mistake. What is the least number of letter swaps needed to fix it?', '["0", "1", "2", "3"]'::jsonb, 1, 'Comparing BRVAE to BRAVE position by position and tracing the misplaced letters into swap cycles gives a minimum of 1 swap(s) to correct. ✓'),
('tj', 'Logic/Reasoning', 'Derek feels dizzy after standing up quickly. Jamal heard 9% of the school has a blood pressure issue. Derek asks if that''s really what''s going on. What''s the most logical reply?', '["You have a 9% chance of having it", "Maybe Derek. But, perhaps not", "Let''s hope you do not have it", "You definitely have a blood pressure issue"]'::jsonb, 1, 'The symptoms described could have many causes besides a blood pressure issue. The honest, logical answer acknowledges the uncertainty rather than jumping to a conclusion. ✓'),
('tj', 'Logic/Reasoning', 'In a gear train A→B→C→D where Gear A rotates clockwise, which direction does Gear D move?', '["Cannot be determined", "clockwise", "In either direction", "counter-clockwise"]'::jsonb, 3, 'Every meshed gear alternates direction from the one before it. Gear D is 3 steps from Gear A, so it ends up rotating counter-clockwise. ✓'),
('tj', 'Logic/Reasoning', 'Three boxes are labeled ''sneakers'', ''sandals'', and ''sneakers and sandals'' — but all labels are wrong. Which box must you open to correctly relabel all three?', '["Box marked ''sandals''", "Any one of the three boxes", "Box marked ''sneakers and sandals''", "Box marked ''sneakers''"]'::jsonb, 2, 'Since every label is wrong, the box marked ''sneakers and sandals'' can''t actually be mixed — it must hold only one item type. Opening just that box reveals its true content, letting you deduce the other two by elimination. ✓'),
('tj', 'Math/Quant', 'Maple Heights''s population increases 12% every 5 years. What is the approximate net percentage change in population after 15 years?', '["44%", "36%", "35%", "40%"]'::jsonb, 3, '15 years is 3 periods of 5 years: growth factor = 1.12^3 ≈ 1.405, a 40% increase. ✓'),
('tj', 'Math/Quant', 'Two 2-Ohm resistors R1 and R2 are in parallel between terminals a and b. Terminal b connects to c, and two more 2-Ohm resistors R3, R4 are in series between c and d. What is the net resistance between a and d?', '["6 Ohms", "8 Ohms", "3 Ohms", "5 Ohms"]'::jsonb, 3, 'R1∥R2 = 2/2 = 1 Ohms. R3+R4 in series = 4 Ohms. Since b and c are joined, total = 1 Ohms + 4 Ohms = 5 Ohms. ✓'),
('tj', 'Math/Quant', 'Fairview''s population increases 15% every 5 years. What is the approximate net percentage change in population after 10 years?', '["32%", "30%", "27%", "36%"]'::jsonb, 0, '10 years is 2 periods of 5 years: growth factor = 1.15^2 ≈ 1.322, a 32% increase. ✓'),
('tj', 'Math/Quant', 'Brookline''s population increases 10% every 5 years. What is the approximate net percentage change in population after 15 years?', '["33%", "30%", "37%", "28%"]'::jsonb, 0, '15 years is 3 periods of 5 years: growth factor = 1.10^3 ≈ 1.331, a 33% increase. ✓'),
('tj', 'Spatial/Geometric', 'How many lines of reflective symmetry and centers of rotational symmetry does a non-rectangular rhombus have?', '["0 lines of reflective symmetry and no center of rotational symmetry", "2 lines of reflective symmetry and one center of rotational symmetry", "3 lines of reflective symmetry and one center of rotational symmetry", "1 lines of reflective symmetry and one center of rotational symmetry"]'::jsonb, 1, 'A non-rectangular rhombus has 2 line(s) of mirror symmetry, and does map onto itself under a partial rotation, giving one center of rotational symmetry. ✓'),
('tj', 'Math/Quant', 'Xena invested $8,000.00 in an account that grows 2% per year. What is the value at the end of year 2?', '["$8,160.00", "$8,320.00", "$7,683.20", "$8,323.20"]'::jsonb, 3, 'Compound growth: value = $8,000.00 × 1.02^2 = $8,323.20. ✓'),
('tj', 'Math/Quant', 'Owen drove to a friend''s house at 50 mph and returned along the same route at 30 mph. What was the average speed for the round trip?', '["50 mph", "40 mph", "30 mph", "37.5 mph"]'::jsonb, 3, 'For equal distances at two speeds, average speed is the harmonic mean: 2(50)(30)/(50+30) = 37.5 mph. ✓'),
('tj', 'Spatial/Geometric', 'A sphere is cut 6 times, all cuts passing through a common axis, evenly spaced. What is the greatest number of pieces possible?', '["6", "12", "11", "14"]'::jsonb, 1, 'n cuts through a common axis produce 2n pieces (like a pizza cut through the center). For n=6: 2×6 = 12 pieces. ✓'),
('tj', 'Logic/Reasoning', 'In a gear train A→B where Gear A rotates clockwise, which direction does Gear B move?', '["counter-clockwise", "clockwise", "In either direction", "Cannot be determined"]'::jsonb, 0, 'Every meshed gear alternates direction from the one before it. Gear B is 1 steps from Gear A, so it ends up rotating counter-clockwise. ✓'),
('tj', 'Math/Quant', 'What is the probability that two randomly selected people share the same month of the year? Assume all 12 options are equally likely.', '["1/12", "11/12", "1/144", "1/11"]'::jsonb, 0, 'The first person''s month of the year doesn''t matter. The second person just needs to match it: probability = 1/12. ✓'),
('tj', 'Math/Quant', 'A pie chart sector represents 12% of the data. What is the sector''s angle?', '["35.2\u00b0", "43.2\u00b0", "53.2\u00b0", "36\u00b0"]'::jsonb, 1, 'Sector angle = percentage × 360° = 12% × 360° = 43.2°. ✓'),
('tj', 'Math/Quant', 'Owen drove to a friend''s house at 60 mph and returned along the same route at 20 mph. What was the average speed for the round trip?', '["40 mph", "20 mph", "60 mph", "30 mph"]'::jsonb, 3, 'For equal distances at two speeds, average speed is the harmonic mean: 2(60)(20)/(60+20) = 30 mph. ✓'),
('tj', 'Math/Quant', 'A pie chart sector represents 5% of the data. What is the sector''s angle?', '["15\u00b0", "18\u00b0", "10\u00b0", "28\u00b0"]'::jsonb, 1, 'Sector angle = percentage × 360° = 5% × 360° = 18°. ✓'),
('tj', 'Spatial/Geometric', 'A red-painted cube (7×7×7 unit cubes) is cut apart. How many unit cubes have no more than one face painted red?', '["275", "60", "150", "125"]'::jsonb, 0, 'Cubes with 1 painted face: 6(n−2)² = 6(25) = 150. Cubes with 0 painted faces: (n−2)³ = 125. Total with ≤1 face painted: 150 + 125 = 275. ✓'),
('tj', 'Math/Quant', 'What is the probability that two randomly selected people share the same side when rolling a standard die? Assume all 6 options are equally likely.', '["5/6", "1/36", "1/6", "1/5"]'::jsonb, 2, 'The first person''s side when rolling a standard die doesn''t matter. The second person just needs to match it: probability = 1/6. ✓'),
('tj', 'Logic/Reasoning', 'Ben feels dizzy after standing up quickly. Tara heard 9% of the school has a blood pressure issue. Ben asks if that''s really what''s going on. What''s the most logical reply?', '["Let''s hope you do not have it", "You have a 9% chance of having it", "Maybe Ben. But, perhaps not", "You definitely have a blood pressure issue"]'::jsonb, 2, 'The symptoms described could have many causes besides a blood pressure issue. The honest, logical answer acknowledges the uncertainty rather than jumping to a conclusion. ✓'),
('tj', 'Math/Quant', 'Umar invested $1,000.00 in an account that grows 8% per year. What is the value at the end of year 2?', '["$1,160.00", "$1,080.00", "$1,166.40", "$846.40"]'::jsonb, 2, 'Compound growth: value = $1,000.00 × 1.08^2 = $1,166.40. ✓'),
